parameters.content:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels:
 * email, SMS, and webhook. Each channel has independent enable/subscribe settings.
 *
 * Originally email-only (Session 3), extended to multi-channel after SMS support
 * was added (Session 8) and webhook support was already present.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * How frequently a user wants to receive email notifications.
 * - 'instant': Send immediately when triggered
 * - 'daily': Batch into a daily digest
 * - 'weekly': Batch into a weekly digest
 */
export type EmailFrequency = 'instant' | 'daily' | 'weekly';

/**
 * Base notification settings shared by all channels.
 */
export interface ChannelNotificationSettings {
  /** Whether this channel is enabled at all. */
  enabled: boolean;

  /**
   * Notification categories the user is subscribed to on this channel.
   * If a NotificationType is not in this set, the user won't receive it on this channel.
   */
  subscribedCategories: NotificationType[];
}

/**
 * Email-specific notification settings.
 */
export interface EmailNotificationSettings extends ChannelNotificationSettings {
  /** Delivery frequency for non-urgent notifications. */
  frequency: EmailFrequency;
}

/**
 * SMS-specific notification settings.
 */
export interface SmsNotificationSettings extends ChannelNotificationSettings {}

/**
 * Webhook-specific notification settings.
 */
export interface WebhookNotificationSettings extends ChannelNotificationSettings {}

/**
 * Full user notification preferences across all channels.
 */
export interface UserNotificationPreferences {
  userId: string;
  email: EmailNotificationSettings;
  sms: SmsNotificationSettings;
  webhook: WebhookNotificationSettings;
  updatedAt: Date;
}

/**
 * Input for updating a user's notification preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdatePreferencesInput {
  email?: {
    enabled?: boolean;
    frequency?: EmailFrequency;
    subscribedCategories?: NotificationType[];
  };
  sms?: {
    enabled?: boolean;
    subscribedCategories?: NotificationType[];
  };
  webhook?: {
    enabled?: boolean;
    subscribedCategories?: NotificationType[];
  };
}

/**
 * All notification categories.
 */
const ALL_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
];

/**
 * Returns default notification preferences for a new user.
 * All categories enabled on all channels, instant email frequency.
 */
export function getDefaultPreferences(userId: string): UserNotificationPreferences {
  return {
    userId,
    email: {
      enabled: true,
      frequency: 'instant',
      subscribedCategories: [...ALL_CATEGORIES],
    },
    sms: {
      enabled: true,
      subscribedCategories: [...ALL_CATEGORIES],
    },
    webhook: {
      enabled: true,
      subscribedCategories: [...ALL_CATEGORIES],
    },
    updatedAt: new Date(),
  };
}

/**
 * Get the channel settings from a preferences object for a given channel.
 */
export function getChannelSettings(
  prefs: UserNotificationPreferences,
  channel: NotificationChannel,
): ChannelNotificationSettings | undefined {
  switch (channel) {
    case 'email':
      return prefs.email;
    case 'sms':
      return prefs.sms;
    case 'webhook':
      return prefs.webhook;
    default:
      return undefined;
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification preferences and
 * methods to check whether a specific notification should be sent
 * to a user on any channel based on their current settings.
 *
 * Storage is in-memory, consistent with other services in this codebase.
 */

import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { getDefaultPreferences, getChannelSettings } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

function clonePreferences(prefs: UserNotificationPreferences): UserNotificationPreferences {
  return {
    ...prefs,
    email: { ...prefs.email, subscribedCategories: [...prefs.email.subscribedCategories] },
    sms: { ...prefs.sms, subscribedCategories: [...prefs.sms.subscribedCategories] },
    webhook: { ...prefs.webhook, subscribedCategories: [...prefs.webhook.subscribedCategories] },
  };
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get a user's notification preferences.
   * Returns default preferences if the user has not customized them.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return clonePreferences(existing);
    }
    const defaults = getDefaultPreferences(userId);
    this.preferences.set(userId, defaults);
    return clonePreferences(defaults);
  }

  /**
   * Update a user's notification preferences.
   * Only provided fields are updated; others are preserved.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    if (input.email) {
      if (input.email.enabled !== undefined) {
        current.email.enabled = input.email.enabled;
      }
      if (input.email.frequency !== undefined) {
        current.email.frequency = input.email.frequency;
      }
      if (input.email.subscribedCategories !== undefined) {
        current.email.subscribedCategories = [...input.email.subscribedCategories];
      }
    }

    if (input.sms) {
      if (input.sms.enabled !== undefined) {
        current.sms.enabled = input.sms.enabled;
      }
      if (input.sms.subscribedCategories !== undefined) {
        current.sms.subscribedCategories = [...input.sms.subscribedCategories];
      }
    }

    if (input.webhook) {
      if (input.webhook.enabled !== undefined) {
        current.webhook.enabled = input.webhook.enabled;
      }
      if (input.webhook.subscribedCategories !== undefined) {
        current.webhook.subscribedCategories = [...input.webhook.subscribedCategories];
      }
    }

    current.updatedAt = new Date();
    this.preferences.set(userId, current);
    this.logger.info(`Updated preferences for user ${userId}`);

    return clonePreferences(current);
  }

  /**
   * Check whether a notification of the given type should be sent to a user
   * on the specified channel based on their preferences.
   *
   * Returns true if:
   * - The channel is enabled AND
   * - The notification type is in the user's subscribed categories for that channel
   *
   * For channels without explicit preference support (e.g., in-app), returns true.
   */
  shouldSend(userId: string, notificationType: NotificationType, channel: NotificationChannel): boolean {
    const prefs = this.getPreferences(userId);
    const channelSettings = getChannelSettings(prefs, channel);

    if (!channelSettings) {
      // Channel not managed by preferences (e.g., in-app) — allow by default
      return true;
    }

    if (!channelSettings.enabled) {
      this.logger.info(`${channel} disabled for user ${userId}, suppressing ${notificationType}`);
      return false;
    }

    if (!channelSettings.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType} on ${channel}, suppressing`);
      return false;
    }

    return true;
  }

  /**
   * Check whether a notification should be sent via email.
   * Backward-compatible convenience method — delegates to shouldSend().
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, notificationType, 'email');
  }

  /**
   * Remove a user's custom preferences (revert to defaults on next access).
   */
  resetPreferences(userId: string): void {
    this.preferences.delete(userId);
    this.logger.info(`Reset preferences for user ${userId}`);
  }

  /**
   * Clear all stored preferences. Useful for testing.
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

