import { describe, it, expect, beforeEach } from 'vitest';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let service: PreferencesService;

  beforeEach(() => {
    service = new PreferencesService();
  });

  describe('getPreferences', () => {
    it('should return default preferences for a new user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('instant');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_update',
      ]);
    });

    it('should return default SMS preferences for a new user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_update',
      ]);
    });

    it('should return default webhook preferences for a new user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_update',
      ]);
    });

    it('should return a defensive copy', () => {
      const prefs1 = service.getPreferences('user-1');
      prefs1.email.enabled = false;
      prefs1.email.subscribedCategories.push('order_confirmation');
      prefs1.sms.enabled = false;

      const prefs2 = service.getPreferences('user-1');
      expect(prefs2.email.enabled).toBe(true);
      expect(prefs2.sms.enabled).toBe(true);
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled setting', () => {
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('instant'); // unchanged
    });

    it('should update email frequency', () => {
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order_confirmation'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update SMS preferences', () => {
      const updated = service.updatePreferences('user-1', {
        sms: { enabled: false },
      });

      expect(updated.sms.enabled).toBe(false);
      expect(updated.email.enabled).toBe(true); // other channels unaffected
    });

    it('should update SMS subscribed categories', () => {
      const updated = service.updatePreferences('user-1', {
        sms: { subscribedCategories: ['order_confirmation'] },
      });

      expect(updated.sms.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should update webhook preferences', () => {
      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: false },
      });

      expect(updated.webhook.enabled).toBe(false);
      expect(updated.email.enabled).toBe(true); // other channels unaffected
      expect(updated.sms.enabled).toBe(true);
    });

    it('should update webhook subscribed categories', () => {
      const updated = service.updatePreferences('user-1', {
        webhook: { subscribedCategories: ['welcome'] },
      });

      expect(updated.webhook.subscribedCategories).toEqual(['welcome']);
    });

    it('should update multiple channels at once', () => {
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { subscribedCategories: ['order_confirmation'] },
        webhook: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms.subscribedCategories).toEqual(['order_confirmation']);
      expect(updated.webhook.enabled).toBe(false);
    });

    it('should persist updates across calls', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false, frequency: 'weekly' },
      });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('weekly');
    });

    it('should update updatedAt timestamp', () => {
      const before = new Date();
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
    });

    it('should return a defensive copy', () => {
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['welcome'] },
      });
      updated.email.subscribedCategories.push('order_confirmation');

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.subscribedCategories).toEqual(['welcome']);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true for default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false for unsubscribed categories', () => {
      service.updatePreferences('user-1', {
        email: { subscribedCategories: ['welcome'] },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return false when email disabled even if category subscribed', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false, subscribedCategories: ['order_confirmation'] },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('shouldSend (multi-channel)', () => {
    it('should check SMS preferences', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(true);

      service.updatePreferences('user-1', { sms: { enabled: false } });
      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(false);
    });

    it('should check SMS subscribed categories', () => {
      service.updatePreferences('user-1', {
        sms: { subscribedCategories: ['welcome'] },
      });

      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(false);
      expect(service.shouldSend('user-1', 'welcome', 'sms')).toBe(true);
    });

    it('should check webhook preferences', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(true);

      service.updatePreferences('user-1', { webhook: { enabled: false } });
      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(false);
    });

    it('should check webhook subscribed categories', () => {
      service.updatePreferences('user-1', {
        webhook: { subscribedCategories: ['account_update'] },
      });

      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(false);
      expect(service.shouldSend('user-1', 'account_update', 'webhook')).toBe(true);
    });

    it('should allow in-app channel (no preferences defined)', () => {
      expect(service.shouldSend('user-1', 'order_confirmation', 'in-app')).toBe(true);
    });

    it('should handle channels independently', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { subscribedCategories: ['welcome'] },
      });

      expect(service.shouldSend('user-1', 'order_confirmation', 'email')).toBe(false);
      expect(service.shouldSend('user-1', 'order_confirmation', 'sms')).toBe(true);
      expect(service.shouldSend('user-1', 'order_confirmation', 'webhook')).toBe(false);
      expect(service.shouldSend('user-1', 'welcome', 'webhook')).toBe(true);
    });
  });

  describe('resetPreferences', () => {
    it('should revert to defaults after reset', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false, frequency: 'weekly' },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      service.resetPreferences('user-1');
      const prefs = service.getPreferences('user-1');

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('instant');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.webhook.enabled).toBe(true);
    });
  });

  describe('clearAll', () => {
    it('should clear all stored preferences', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      service.updatePreferences('user-2', { email: { frequency: 'daily' } });

      service.clearAll();

      // Both should return defaults
      expect(service.getPreferences('user-1').email.enabled).toBe(true);
      expect(service.getPreferences('user-2').email.frequency).toBe('instant');
    });
  });
});

describe('NotificationService with PreferencesService', () => {
  let eventBus: EventBus;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    preferencesService = new PreferencesService();
    notificationService = new NotificationService(eventBus, preferencesService);
    resetNotificationIdCounter();
  });

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  it('should send notifications with default preferences', async () => {
    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotifications()).toHaveLength(1);
  });

  it('should suppress notifications when email is disabled', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { enabled: false },
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should suppress notifications for unsubscribed categories', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { subscribedCategories: ['welcome'] },
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should allow notifications for subscribed categories', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { subscribedCategories: ['order_confirmation'] },
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotifications()).toHaveLength(1);
  });

  it('should suppress order status updates when unsubscribed', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { subscribedCategories: ['order_confirmation'] },
    });

    await eventBus.emit(statusChangedEvent);

    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should work without preferences service (backward compatible)', async () => {
    const serviceWithoutPrefs = new NotificationService(eventBus);

    await eventBus.emit(orderCreatedEvent);

    // Both services receive the event — the one without prefs should send
    // We need a fresh eventBus to test isolation
    const freshBus = new EventBus();
    const freshService = new NotificationService(freshBus);
    await freshBus.emit(orderCreatedEvent);

    expect(freshService.getNotifications()).toHaveLength(1);
  });
});
